package com.duybao.SplitGo.DTO.Response.ecommerce;

import com.duybao.SplitGo.Enum.ProductStatus;
import java.math.BigDecimal;
import java.time.LocalDateTime;
import lombok.Builder;
import lombok.Data;

@Data
@Builder
public class ProductResponse {
    private Long id;
    private String name;
    private String description;
    private String imageUrl;
    private BigDecimal price;
    private Integer stock;
    private Long viewCount;
    private ProductStatus status;
    private Long sellerId;
    private String sellerUsername;
    private Long categoryId;
    private String categoryName;
    private LocalDateTime createdAt;
    private LocalDateTime updatedAt;
}

package com.duybao.SplitGo.Model;

import com.duybao.SplitGo.Enum.ProductStatus;
import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.EnumType;
import jakarta.persistence.Enumerated;
import jakarta.persistence.FetchType;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.JoinColumn;
import jakarta.persistence.ManyToOne;
import jakarta.persistence.PrePersist;
import jakarta.persistence.PreUpdate;
import jakarta.persistence.Table;
import java.math.BigDecimal;
import java.time.LocalDateTime;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Getter;
import lombok.NoArgsConstructor;
import lombok.Setter;

@Entity
@Table(name = "products")
@Getter
@Setter
@NoArgsConstructor
@AllArgsConstructor
@Builder
public class Product {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false)
    private String name;

    @Column(length = 4000)
    private String description;

    @Column(nullable = false, precision = 19, scale = 2)
    private BigDecimal price;

    @Column(nullable = false)
    private Integer stock;

    @Column(nullable = false)
    private String imageUrl;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    private ProductStatus status;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "seller_id", nullable = false)
    private User seller;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "category_id")
    private Category category;

    @Column(nullable = false)
    private LocalDateTime createdAt;

    @Column(nullable = false)
    private LocalDateTime updatedAt;

    @PrePersist
    public void prePersist() {
        LocalDateTime now = LocalDateTime.now();
        if (createdAt == null) {
            createdAt = now;
        }
        if (updatedAt == null) {
            updatedAt = now;
        }
        if (status == null) {
            status = ProductStatus.ACTIVE;
        }
    }

    @PreUpdate
    public void preUpdate() {
        updatedAt = LocalDateTime.now();
    }
}

package com.duybao.SplitGo.Model;

import com.duybao.SplitGo.Enum.ProductStatus;
import jakarta.persistence.Column;
import jakarta.persistence.Entity;
import jakarta.persistence.EnumType;
import jakarta.persistence.Enumerated;
import jakarta.persistence.FetchType;
import jakarta.persistence.GeneratedValue;
import jakarta.persistence.GenerationType;
import jakarta.persistence.Id;
import jakarta.persistence.JoinColumn;
import jakarta.persistence.ManyToOne;
import jakarta.persistence.PrePersist;
import jakarta.persistence.PreUpdate;
import jakarta.persistence.Table;
import java.math.BigDecimal;
import java.time.LocalDateTime;
import lombok.AllArgsConstructor;
import lombok.Builder;
import lombok.Getter;
import lombok.NoArgsConstructor;
import lombok.Setter;

@Entity
@Table(name = "products")
@Getter
@Setter
@NoArgsConstructor
@AllArgsConstructor
@Builder
public class Product {
    @Id
    @GeneratedValue(strategy = GenerationType.IDENTITY)
    private Long id;

    @Column(nullable = false)
    private String name;

    @Column(length = 4000)
    private String description;

    @Column(nullable = false, precision = 19, scale = 2)
    private BigDecimal price;

    @Column(nullable = false)
    private Integer stock;

    @Column(nullable = false)
    private Long viewCount;

    @Column(nullable = false)
    private String imageUrl;

    @Enumerated(EnumType.STRING)
    @Column(nullable = false)
    private ProductStatus status;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "seller_id", nullable = false)
    private User seller;

    @ManyToOne(fetch = FetchType.LAZY)
    @JoinColumn(name = "category_id")
    private Category category;

    @Column(nullable = false)
    private LocalDateTime createdAt;

    @Column(nullable = false)
    private LocalDateTime updatedAt;

    @PrePersist
    public void prePersist() {
        LocalDateTime now = LocalDateTime.now();
        if (createdAt == null) {
            createdAt = now;
        }
        if (updatedAt == null) {
            updatedAt = now;
        }
        if (status == null) {
            status = ProductStatus.ACTIVE;
        }
        if (viewCount == null) {
            viewCount = 0L;
        }
    }

    @PreUpdate
    public void preUpdate() {
        updatedAt = LocalDateTime.now();
    }
}

package com.duybao.SplitGo.Service.Impl;

import com.duybao.SplitGo.DTO.Response.ecommerce.ProductResponse;
import com.duybao.SplitGo.DTO.request.ecommerce.CreateProductRequest;
import com.duybao.SplitGo.DTO.request.ecommerce.UpdateProductRequest;
import com.duybao.SplitGo.Enum.ProductStatus;
import com.duybao.SplitGo.Exception.AppException;
import com.duybao.SplitGo.Exception.ErrorCode;
import com.duybao.SplitGo.Model.Category;
import com.duybao.SplitGo.Model.Product;
import com.duybao.SplitGo.Model.User;
import com.duybao.SplitGo.Repository.CategoryRepository;
import com.duybao.SplitGo.Repository.ProductRepository;
import com.duybao.SplitGo.Repository.UserRepository;
import com.duybao.SplitGo.Service.CatalogService;
import com.duybao.SplitGo.Service.FileUploadService;
import jakarta.transaction.Transactional;
import java.util.List;
import org.springframework.stereotype.Service;
import org.springframework.web.multipart.MultipartFile;

@Service
public class CatalogServiceImpl implements CatalogService {
    private final ProductRepository productRepository;
    private final CategoryRepository categoryRepository;
    private final UserRepository userRepository;
    private final FileUploadService fileUploadService;

    public CatalogServiceImpl(
            ProductRepository productRepository,
            CategoryRepository categoryRepository,
            UserRepository userRepository,
            FileUploadService fileUploadService) {
        this.productRepository = productRepository;
        this.categoryRepository = categoryRepository;
        this.userRepository = userRepository;
        this.fileUploadService = fileUploadService;
    }

    @Override
    public List<ProductResponse> getPublicProducts() {
        return productRepository.findByStatusOrderByCreatedAtDesc(ProductStatus.ACTIVE).stream()
                .map(this::toProductResponse)
                .toList();
    }

    @Override
    public ProductResponse getProductDetail(Long productId) {
        Product product = productRepository
                .findById(productId)
                .orElseThrow(() -> new AppException(ErrorCode.PRODUCT_NOT_FOUND));
        return toProductResponse(product);
    }


    @Override
    @Transactional
    public ProductResponse createProduct(CreateProductRequest request, Long sellerId, MultipartFile imageFile) {
        User seller = userRepository.findById(sellerId).orElseThrow(() -> new AppException(ErrorCode.USER_NOT_FOUND));
        String imageUrl = request.getImageUrl();
        if (imageFile != null && !imageFile.isEmpty()) {
            imageUrl = fileUploadService.uploadProductImage(imageFile);
        }

        Product product = Product.builder()
                .name(request.getName())
                .description(request.getDescription())
                .price(request.getPrice())
                .stock(request.getStock())
                .imageUrl(imageUrl)
                .status(ProductStatus.ACTIVE)
                .seller(seller)
                .category(resolveCategory(request.getCategoryId(), request.getCategoryName()))
                .build();

        return toProductResponse(productRepository.save(product));
    }

    @Override
    @Transactional
    public ProductResponse updateProduct(Long productId, UpdateProductRequest request, Long sellerId) {
        Product product = productRepository
                .findByIdAndSellerId(productId, sellerId)
                .orElseThrow(() -> new AppException(ErrorCode.PRODUCT_NOT_FOUND));

        if (request.getName() != null && !request.getName().isBlank()) {
            product.setName(request.getName());
        }
        if (request.getDescription() != null) {
            product.setDescription(request.getDescription());
        }
        if (request.getPrice() != null) {
            product.setPrice(request.getPrice());
        }
        if (request.getStock() != null) {
            product.setStock(request.getStock());
        }
        if (request.getStatus() != null) {
            product.setStatus(request.getStatus());
        }
        if (request.getCategoryId() != null) {
            Category category = categoryRepository
                    .findById(request.getCategoryId())
                    .orElseThrow(() -> new AppException(ErrorCode.CATEGORY_NOT_FOUND));
            product.setCategory(category);
        }

        return toProductResponse(productRepository.save(product));
    }

    @Override
    @Transactional
    public void deleteProduct(Long productId, Long sellerId) {
        Product product = productRepository
                .findByIdAndSellerId(productId, sellerId)
                .orElseThrow(() -> new AppException(ErrorCode.PRODUCT_NOT_FOUND));
        product.setStatus(ProductStatus.INACTIVE);
        productRepository.save(product);
    }

    private Category resolveCategory(Long categoryId, String categoryName) {
        if (categoryId != null) {
            return categoryRepository.findById(categoryId).orElseThrow(() -> new AppException(ErrorCode.CATEGORY_NOT_FOUND));
        }
        if (categoryName == null || categoryName.isBlank()) {
            return null;
        }
        return categoryRepository.findByNameIgnoreCase(categoryName).orElseGet(() -> categoryRepository.save(Category.builder()
                .name(categoryName)
                .description("Auto-created from seller request")
                .build()));
    }

    private ProductResponse toProductResponse(Product product) {
        return ProductResponse.builder()
                .id(product.getId())
                .name(product.getName())
                .description(product.getDescription())
                .price(product.getPrice())
                .imageUrl(product.getImageUrl())
                .stock(product.getStock())
                .status(product.getStatus())
                .sellerId(product.getSeller().getId())
                .sellerUsername(product.getSeller().getUsername())
                .categoryId(product.getCategory() != null ? product.getCategory().getId() : null)
                .categoryName(product.getCategory() != null ? product.getCategory().getName() : null)
                .createdAt(product.getCreatedAt())
                .updatedAt(product.getUpdatedAt())
                .build();
    }
}

package com.duybao.SplitGo.Service.Impl;

import com.duybao.SplitGo.DTO.Response.ecommerce.ProductResponse;
import com.duybao.SplitGo.DTO.request.ecommerce.CreateProductRequest;
import com.duybao.SplitGo.DTO.request.ecommerce.UpdateProductRequest;
import com.duybao.SplitGo.Enum.ProductStatus;
import com.duybao.SplitGo.Exception.AppException;
import com.duybao.SplitGo.Exception.ErrorCode;
import com.duybao.SplitGo.Model.Category;
import com.duybao.SplitGo.Model.Product;
import com.duybao.SplitGo.Model.User;
import com.duybao.SplitGo.Repository.CategoryRepository;
import com.duybao.SplitGo.Repository.ProductRepository;
import com.duybao.SplitGo.Repository.UserRepository;
import com.duybao.SplitGo.Service.CatalogService;
import com.duybao.SplitGo.Service.FileUploadService;
import jakarta.transaction.Transactional;
import java.util.List;
import org.springframework.stereotype.Service;
import org.springframework.web.multipart.MultipartFile;

@Service
public class CatalogServiceImpl implements CatalogService {
    private final ProductRepository productRepository;
    private final CategoryRepository categoryRepository;
    private final UserRepository userRepository;
    private final FileUploadService fileUploadService;

    public CatalogServiceImpl(
            ProductRepository productRepository,
            CategoryRepository categoryRepository,
            UserRepository userRepository,
            FileUploadService fileUploadService) {
        this.productRepository = productRepository;
        this.categoryRepository = categoryRepository;
        this.userRepository = userRepository;
        this.fileUploadService = fileUploadService;
    }

    @Override
    public List<ProductResponse> getPublicProducts() {
        return productRepository.findByStatusOrderByCreatedAtDesc(ProductStatus.ACTIVE).stream()
                .map(this::toProductResponse)
                .toList();
    }

    @Override
    @Transactional
    public ProductResponse getProductDetail(Long productId) {
        Product product = productRepository
                .findById(productId)
                .orElseThrow(() -> new AppException(ErrorCode.PRODUCT_NOT_FOUND));
        Long currentViews = product.getViewCount() == null ? 0L : product.getViewCount();
        product.setViewCount(currentViews + 1);
        productRepository.save(product);
        return toProductResponse(product);
    }


    @Override
    @Transactional
    public ProductResponse createProduct(CreateProductRequest request, Long sellerId, MultipartFile imageFile) {
        User seller = userRepository.findById(sellerId).orElseThrow(() -> new AppException(ErrorCode.USER_NOT_FOUND));
        String imageUrl = request.getImageUrl();
        if (imageFile != null && !imageFile.isEmpty()) {
            imageUrl = fileUploadService.uploadProductImage(imageFile);
        }

        Product product = Product.builder()
                .name(request.getName())
                .description(request.getDescription())
                .price(request.getPrice())
                .stock(request.getStock())
                .imageUrl(imageUrl)
                .status(ProductStatus.ACTIVE)
                .seller(seller)
                .category(resolveCategory(request.getCategoryId(), request.getCategoryName()))
                .build();

        return toProductResponse(productRepository.save(product));
    }

    @Override
    @Transactional
    public ProductResponse updateProduct(Long productId, UpdateProductRequest request, Long sellerId) {
        Product product = productRepository
                .findByIdAndSellerId(productId, sellerId)
                .orElseThrow(() -> new AppException(ErrorCode.PRODUCT_NOT_FOUND));

        if (request.getName() != null && !request.getName().isBlank()) {
            product.setName(request.getName());
        }
        if (request.getDescription() != null) {
            product.setDescription(request.getDescription());
        }
        if (request.getPrice() != null) {
            product.setPrice(request.getPrice());
        }
        if (request.getStock() != null) {
            product.setStock(request.getStock());
        }
        if (request.getStatus() != null) {
            product.setStatus(request.getStatus());
        }
        if (request.getCategoryId() != null) {
            Category category = categoryRepository
                    .findById(request.getCategoryId())
                    .orElseThrow(() -> new AppException(ErrorCode.CATEGORY_NOT_FOUND));
            product.setCategory(category);
        }

        return toProductResponse(productRepository.save(product));
    }

    @Override
    @Transactional
    public void deleteProduct(Long productId, Long sellerId) {
        Product product = productRepository
                .findByIdAndSellerId(productId, sellerId)
                .orElseThrow(() -> new AppException(ErrorCode.PRODUCT_NOT_FOUND));
        product.setStatus(ProductStatus.INACTIVE);
        productRepository.save(product);
    }

    private Category resolveCategory(Long categoryId, String categoryName) {
        if (categoryId != null) {
            return categoryRepository.findById(categoryId).orElseThrow(() -> new AppException(ErrorCode.CATEGORY_NOT_FOUND));
        }
        if (categoryName == null || categoryName.isBlank()) {
            return null;
        }
        return categoryRepository.findByNameIgnoreCase(categoryName).orElseGet(() -> categoryRepository.save(Category.builder()
                .name(categoryName)
                .description("Auto-created from seller request")
                .build()));
    }

    private ProductResponse toProductResponse(Product product) {
        return ProductResponse.builder()
                .id(product.getId())
                .name(product.getName())
                .description(product.getDescription())
                .price(product.getPrice())
                .imageUrl(product.getImageUrl())
                .stock(product.getStock())
                .viewCount(product.getViewCount() == null ? 0L : product.getViewCount())
                .status(product.getStatus())
                .sellerId(product.getSeller().getId())
                .sellerUsername(product.getSeller().getUsername())
                .categoryId(product.getCategory() != null ? product.getCategory().getId() : null)
                .categoryName(product.getCategory() != null ? product.getCategory().getName() : null)
                .createdAt(product.getCreatedAt())
                .updatedAt(product.getUpdatedAt())
                .build();
    }
}

import React, { useEffect, useMemo, useState } from 'react'
import { Link } from 'react-router-dom'
import { motion } from 'motion/react'
import { getProducts } from '../services/productService'
import { getCategories } from '../services/categoryService'

const listVariants = {
  hidden: {},
  visible: {
    transition: {
      staggerChildren: 0.06,
      delayChildren: 0.04,
    },
  },
}

const itemVariants = {
  hidden: { opacity: 0, y: 12 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.28, ease: 'easeOut' },
  },
}

function formatPrice(value) {
  return new Intl.NumberFormat('vi-VN', {
    style: 'currency',
    currency: 'VND',
    maximumFractionDigits: 0,
  }).format(value || 0)
}

function normalizeText(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim()
}

function ProductSection() {
  const [products, setProducts] = useState([])
  const [categories, setCategories] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [searchTerm, setSearchTerm] = useState('')
  const [selectedCategory, setSelectedCategory] = useState('all')
  const [stockFilter, setStockFilter] = useState('all')
  const [minPrice, setMinPrice] = useState('')
  const [maxPrice, setMaxPrice] = useState('')
  const [priceSort, setPriceSort] = useState('default')
  const [isFilterPanelOpen, setIsFilterPanelOpen] = useState(false)

  useEffect(() => {
    let cancelled = false

    async function loadProducts() {
      setLoading(true)
      setError('')

      try {
        const items = await getProducts()

        if (!cancelled) {
          setProducts(items)
        }
      } catch (err) {
        if (!cancelled) {
          setError(err?.message || 'Đã có lỗi khi tải sản phẩm')
          setProducts([])
        }
      } finally {
        if (!cancelled) {
          setLoading(false)
        }
      }
    }

    loadProducts()

    return () => {
      cancelled = true
    }
  }, [])

  useEffect(() => {
    let cancelled = false

    async function loadCategories() {
      try {
        const items = await getCategories()
        if (!cancelled) {
          setCategories(items)
        }
      } catch {
        if (!cancelled) {
          setCategories([])
        }
      }
    }

    loadCategories()

    return () => {
      cancelled = true
    }
  }, [])

  const filteredProducts = useMemo(() => {
    const keyword = normalizeText(searchTerm)
    const min = Number(minPrice)
    const max = Number(maxPrice)
    const hasMin = Number.isFinite(min) && min > 0
    const hasMax = Number.isFinite(max) && max > 0

    const result = products.filter((product) => {
      const productName = normalizeText(product?.name)
      const matchName = !keyword || productName.includes(keyword)

      const categoryId = String(product?.categoryId || '')
      const matchCategory = selectedCategory === 'all' || categoryId === selectedCategory

      const stock = Number(product?.stock || 0)
      const matchStock =
        stockFilter === 'all' ||
        (stockFilter === 'inStock' && stock > 0) ||
        (stockFilter === 'outOfStock' && stock <= 0) ||
        (stockFilter === 'lowStock' && stock > 0 && stock <= 10)

      const price = Number(product?.price || 0)
      const matchMinPrice = !hasMin || price >= min
      const matchMaxPrice = !hasMax || price <= max

      return matchName && matchCategory && matchStock && matchMinPrice && matchMaxPrice
    })

    if (priceSort === 'asc') {
      result.sort((a, b) => Number(a?.price || 0) - Number(b?.price || 0))
    }

    if (priceSort === 'desc') {
      result.sort((a, b) => Number(b?.price || 0) - Number(a?.price || 0))
    }

    return result
  }, [products, searchTerm, selectedCategory, stockFilter, minPrice, maxPrice, priceSort])

  return (
    <section id="products" className="mt-14">
      <div className="flex flex-wrap items-end justify-between gap-3">
        <div>
          <p className="text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">Sản phẩm</p>
          <h2 className="mt-2 text-3xl font-semibold tracking-tight text-zinc-900">Danh sách sản phẩm mới nhất</h2>
        </div>
        <div className="flex items-center gap-2">
          <button
            type="button"
            onClick={() => setIsFilterPanelOpen((prev) => !prev)}
            className="rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900"
          >
            {isFilterPanelOpen ? 'Ẩn bộ lọc' : 'Bộ lọc'}
          </button>
        </div>
      </div>

      {isFilterPanelOpen && (
      <div className="mt-4 rounded-2xl border border-zinc-200 bg-white p-4">
        <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3">
          <div className="md:col-span-2 lg:col-span-3">
            <label htmlFor="product-search" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Tìm kiếm theo tên sản phẩm
            </label>
            <input
              id="product-search"
              type="text"
              value={searchTerm}
              onChange={(event) => setSearchTerm(event.target.value)}
              placeholder="Nhập tên sản phẩm..."
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-4 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            />
          </div>

          <div>
            <label htmlFor="category-filter" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Danh mục
            </label>
            <select
              id="category-filter"
              value={selectedCategory}
              onChange={(event) => setSelectedCategory(event.target.value)}
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            >
              <option value="all">Tất cả danh mục</option>
              {categories.map((category) => (
                <option key={category.id} value={String(category.id)}>
                  {category.name}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label htmlFor="stock-filter" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Số lượng
            </label>
            <select
              id="stock-filter"
              value={stockFilter}
              onChange={(event) => setStockFilter(event.target.value)}
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            >
              <option value="all">Tất cả</option>
              <option value="inStock">Còn hàng</option>
              <option value="outOfStock">Hết hàng</option>
              <option value="lowStock">Sắp hết (1-10)</option>
            </select>
          </div>

          <div>
            <label htmlFor="price-sort" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Giá tiền
            </label>
            <select
              id="price-sort"
              value={priceSort}
              onChange={(event) => setPriceSort(event.target.value)}
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            >
              <option value="default">Mặc định</option>
              <option value="asc">Thấp đến cao</option>
              <option value="desc">Cao đến thấp</option>
            </select>
          </div>

          <div>
            <label htmlFor="min-price" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Giá từ
            </label>
            <input
              id="min-price"
              type="number"
              min="0"
              value={minPrice}
              onChange={(event) => setMinPrice(event.target.value)}
              placeholder="0"
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            />
          </div>

          <div>
            <label htmlFor="max-price" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Giá đến
            </label>
            <input
              id="max-price"
              type="number"
              min="0"
              value={maxPrice}
              onChange={(event) => setMaxPrice(event.target.value)}
              placeholder="99999999"
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            />
          </div>
        </div>
      </div>
      )}

      {loading && (
        <div className="mt-6 rounded-2xl border border-zinc-200 bg-white p-6 text-sm text-zinc-600">
          Đang tải sản phẩm...
        </div>
      )}

      {!loading && error && (
        <div className="mt-6 rounded-2xl border border-red-200 bg-red-50 p-6 text-sm text-red-700">
          Không thể tải sản phẩm: {error}
        </div>
      )}

      {!loading && !error && products.length === 0 && (
        <div className="mt-6 rounded-2xl border border-zinc-200 bg-white p-6 text-sm text-zinc-600">
          Chưa có sản phẩm nào để hiển thị.
        </div>
      )}

      {!loading && !error && products.length > 0 && filteredProducts.length === 0 && (
        <div className="mt-6 rounded-2xl border border-amber-200 bg-amber-50 p-6 text-sm text-amber-800">
          Không tìm thấy sản phẩm phù hợp với từ khóa "{searchTerm.trim()}".
        </div>
      )}

      {!loading && !error && filteredProducts.length > 0 && (
        <motion.div
          variants={listVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: 0.2 }}
          className="mt-6 grid gap-4 md:grid-cols-2"
        >
          {filteredProducts.map((product) => (
            <motion.article
              key={product.id}
              variants={itemVariants}
              className="overflow-hidden rounded-2xl border border-zinc-200 bg-white"
            >
              <div className="h-44 bg-zinc-100">
                {product.imageUrl ? (
                  <img
                    src={product.imageUrl}
                    alt={product.name}
                    className="h-full w-full object-cover"
                  />
                ) : (
                  <div className="flex h-full items-center justify-center bg-gradient-to-br from-zinc-200 to-zinc-100 text-sm font-semibold text-zinc-500">
                    Chưa có ảnh sản phẩm
                  </div>
                )}
              </div>

              <div className="p-5">
                <div className="flex items-start justify-between gap-3">
                  <h3 className="text-lg font-semibold text-zinc-900">{product.name}</h3>
                  <span className="rounded-full border border-zinc-200 bg-zinc-100 px-2.5 py-1 text-[11px] font-semibold uppercase tracking-[0.15em] text-zinc-600">
                    {product.status}
                  </span>
                </div>

                <p className="mt-2 line-clamp-2 text-sm text-zinc-600">{product.description}</p>

                <div className="mt-4 grid grid-cols-2 gap-2 text-sm text-zinc-600">
                  <p>Danh mục: <span className="font-medium text-zinc-900">{product.categoryName}</span></p>
                  <p>Kho: <span className="font-medium text-zinc-900">{product.stock}</span></p>
                  <p>Người bán: <span className="font-medium text-zinc-900">{product.sellerUsername}</span></p>
                  <p>ID: <span className="font-medium text-zinc-900">#{product.id}</span></p>
                </div>

                <div className="mt-5 flex items-center justify-between">
                   <p className="text-xl font-semibold text-zinc-900">{formatPrice(product.price)}</p>
                   <Link
                     to={`/products/${product.id}`}
                     className="rounded-full bg-zinc-900 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-white hover:bg-zinc-700"
                   >
                     Xem chi tiết
                   </Link>
                 </div>
              </div>
            </motion.article>
          ))}
        </motion.div>
      )}
    </section>
  )
}

export default ProductSection

import React, { useEffect, useMemo, useState } from 'react'
import { Link } from 'react-router-dom'
import { motion } from 'motion/react'
import { getProducts } from '../services/productService'
import { getCategories } from '../services/categoryService'

const listVariants = {
  hidden: {},
  visible: {
    transition: {
      staggerChildren: 0.06,
      delayChildren: 0.04,
    },
  },
}

const itemVariants = {
  hidden: { opacity: 0, y: 12 },
  visible: {
    opacity: 1,
    y: 0,
    transition: { duration: 0.28, ease: 'easeOut' },
  },
}

function formatPrice(value) {
  return new Intl.NumberFormat('vi-VN', {
    style: 'currency',
    currency: 'VND',
    maximumFractionDigits: 0,
  }).format(value || 0)
}

function normalizeText(value) {
  return String(value || '')
    .normalize('NFD')
    .replace(/[\u0300-\u036f]/g, '')
    .toLowerCase()
    .trim()
}

function ProductSection() {
  const [products, setProducts] = useState([])
  const [categories, setCategories] = useState([])
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [searchTerm, setSearchTerm] = useState('')
  const [selectedCategory, setSelectedCategory] = useState('all')
  const [stockFilter, setStockFilter] = useState('all')
  const [minPrice, setMinPrice] = useState('')
  const [maxPrice, setMaxPrice] = useState('')
  const [priceSort, setPriceSort] = useState('default')
  const [isFilterPanelOpen, setIsFilterPanelOpen] = useState(false)

  useEffect(() => {
    let cancelled = false

    async function loadProducts() {
      setLoading(true)
      setError('')

      try {
        const items = await getProducts()

        if (!cancelled) {
          setProducts(items)
        }
      } catch (err) {
        if (!cancelled) {
          setError(err?.message || 'Đã có lỗi khi tải sản phẩm')
          setProducts([])
        }
      } finally {
        if (!cancelled) {
          setLoading(false)
        }
      }
    }

    loadProducts()

    return () => {
      cancelled = true
    }
  }, [])

  useEffect(() => {
    let cancelled = false

    async function loadCategories() {
      try {
        const items = await getCategories()
        if (!cancelled) {
          setCategories(items)
        }
      } catch {
        if (!cancelled) {
          setCategories([])
        }
      }
    }

    loadCategories()

    return () => {
      cancelled = true
    }
  }, [])

  const filteredProducts = useMemo(() => {
    const keyword = normalizeText(searchTerm)
    const min = Number(minPrice)
    const max = Number(maxPrice)
    const hasMin = Number.isFinite(min) && min > 0
    const hasMax = Number.isFinite(max) && max > 0

    const result = products.filter((product) => {
      const productName = normalizeText(product?.name)
      const matchName = !keyword || productName.includes(keyword)

      const categoryId = String(product?.categoryId || '')
      const matchCategory = selectedCategory === 'all' || categoryId === selectedCategory

      const stock = Number(product?.stock || 0)
      const matchStock =
        stockFilter === 'all' ||
        (stockFilter === 'inStock' && stock > 0) ||
        (stockFilter === 'outOfStock' && stock <= 0) ||
        (stockFilter === 'lowStock' && stock > 0 && stock <= 10)

      const price = Number(product?.price || 0)
      const matchMinPrice = !hasMin || price >= min
      const matchMaxPrice = !hasMax || price <= max

      return matchName && matchCategory && matchStock && matchMinPrice && matchMaxPrice
    })

    if (priceSort === 'asc') {
      result.sort((a, b) => Number(a?.price || 0) - Number(b?.price || 0))
    }

    if (priceSort === 'desc') {
      result.sort((a, b) => Number(b?.price || 0) - Number(a?.price || 0))
    }

    return result
  }, [products, searchTerm, selectedCategory, stockFilter, minPrice, maxPrice, priceSort])

  return (
    <section id="products" className="mt-14">
      <div className="flex flex-wrap items-end justify-between gap-3">
        <div>
          <p className="text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">Sản phẩm</p>
          <h2 className="mt-2 text-3xl font-semibold tracking-tight text-zinc-900">Danh sách sản phẩm mới nhất</h2>
        </div>
        <div className="flex items-center gap-2">
          <button
            type="button"
            onClick={() => setIsFilterPanelOpen((prev) => !prev)}
            className="rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900"
          >
            {isFilterPanelOpen ? 'Ẩn bộ lọc' : 'Bộ lọc'}
          </button>
        </div>
      </div>

      {isFilterPanelOpen && (
      <div className="mt-4 rounded-2xl border border-zinc-200 bg-white p-4">
        <div className="grid gap-3 md:grid-cols-2 lg:grid-cols-3">
          <div className="md:col-span-2 lg:col-span-3">
            <label htmlFor="product-search" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Tìm kiếm theo tên sản phẩm
            </label>
            <input
              id="product-search"
              type="text"
              value={searchTerm}
              onChange={(event) => setSearchTerm(event.target.value)}
              placeholder="Nhập tên sản phẩm..."
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-4 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            />
          </div>

          <div>
            <label htmlFor="category-filter" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Danh mục
            </label>
            <select
              id="category-filter"
              value={selectedCategory}
              onChange={(event) => setSelectedCategory(event.target.value)}
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            >
              <option value="all">Tất cả danh mục</option>
              {categories.map((category) => (
                <option key={category.id} value={String(category.id)}>
                  {category.name}
                </option>
              ))}
            </select>
          </div>

          <div>
            <label htmlFor="stock-filter" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Số lượng
            </label>
            <select
              id="stock-filter"
              value={stockFilter}
              onChange={(event) => setStockFilter(event.target.value)}
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            >
              <option value="all">Tất cả</option>
              <option value="inStock">Còn hàng</option>
              <option value="outOfStock">Hết hàng</option>
              <option value="lowStock">Sắp hết (1-10)</option>
            </select>
          </div>

          <div>
            <label htmlFor="price-sort" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Giá tiền
            </label>
            <select
              id="price-sort"
              value={priceSort}
              onChange={(event) => setPriceSort(event.target.value)}
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            >
              <option value="default">Mặc định</option>
              <option value="asc">Thấp đến cao</option>
              <option value="desc">Cao đến thấp</option>
            </select>
          </div>

          <div>
            <label htmlFor="min-price" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Giá từ
            </label>
            <input
              id="min-price"
              type="number"
              min="0"
              value={minPrice}
              onChange={(event) => setMinPrice(event.target.value)}
              placeholder="0"
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            />
          </div>

          <div>
            <label htmlFor="max-price" className="text-xs font-semibold uppercase tracking-[0.16em] text-zinc-500">
              Giá đến
            </label>
            <input
              id="max-price"
              type="number"
              min="0"
              value={maxPrice}
              onChange={(event) => setMaxPrice(event.target.value)}
              placeholder="99999999"
              className="mt-2 w-full rounded-xl border border-zinc-300 bg-white px-3 py-2 text-sm text-zinc-900 outline-none focus:border-zinc-900"
            />
          </div>
        </div>
      </div>
      )}

      {loading && (
        <div className="mt-6 rounded-2xl border border-zinc-200 bg-white p-6 text-sm text-zinc-600">
          Đang tải sản phẩm...
        </div>
      )}

      {!loading && error && (
        <div className="mt-6 rounded-2xl border border-red-200 bg-red-50 p-6 text-sm text-red-700">
          Không thể tải sản phẩm: {error}
        </div>
      )}

      {!loading && !error && products.length === 0 && (
        <div className="mt-6 rounded-2xl border border-zinc-200 bg-white p-6 text-sm text-zinc-600">
          Chưa có sản phẩm nào để hiển thị.
        </div>
      )}

      {!loading && !error && products.length > 0 && filteredProducts.length === 0 && (
        <div className="mt-6 rounded-2xl border border-amber-200 bg-amber-50 p-6 text-sm text-amber-800">
          Không tìm thấy sản phẩm phù hợp với từ khóa "{searchTerm.trim()}".
        </div>
      )}

      {!loading && !error && filteredProducts.length > 0 && (
        <motion.div
          variants={listVariants}
          initial="hidden"
          whileInView="visible"
          viewport={{ once: true, amount: 0.2 }}
          className="mt-6 grid gap-4 md:grid-cols-2"
        >
          {filteredProducts.map((product) => (
            <motion.article
              key={product.id}
              variants={itemVariants}
              className="overflow-hidden rounded-2xl border border-zinc-200 bg-white"
            >
              <div className="h-44 bg-zinc-100">
                {product.imageUrl ? (
                  <img
                    src={product.imageUrl}
                    alt={product.name}
                    className="h-full w-full object-cover"
                  />
                ) : (
                  <div className="flex h-full items-center justify-center bg-gradient-to-br from-zinc-200 to-zinc-100 text-sm font-semibold text-zinc-500">
                    Chưa có ảnh sản phẩm
                  </div>
                )}
              </div>

              <div className="p-5">
                <div className="flex items-start justify-between gap-3">
                  <h3 className="text-lg font-semibold text-zinc-900">{product.name}</h3>
                  <span className="rounded-full border border-zinc-200 bg-zinc-100 px-2.5 py-1 text-[11px] font-semibold uppercase tracking-[0.15em] text-zinc-600">
                    {product.status}
                  </span>
                </div>

                <p className="mt-2 line-clamp-2 text-sm text-zinc-600">{product.description}</p>

                <div className="mt-4 grid grid-cols-2 gap-2 text-sm text-zinc-600">
                  <p>Danh mục: <span className="font-medium text-zinc-900">{product.categoryName}</span></p>
                  <p>Kho: <span className="font-medium text-zinc-900">{product.stock}</span></p>
                  <p>Người bán: <span className="font-medium text-zinc-900">{product.sellerUsername}</span></p>
                  <p>ID: <span className="font-medium text-zinc-900">#{product.id}</span></p>
                </div>

                <p className="mt-2 text-sm text-zinc-600">
                  Lượt xem: <span className="font-medium text-zinc-900">{Number(product?.viewCount || 0).toLocaleString('vi-VN')}</span>
                </p>

                <div className="mt-5 flex items-center justify-between">
                   <p className="text-xl font-semibold text-zinc-900">{formatPrice(product.price)}</p>
                   <Link
                     to={`/products/${product.id}`}
                     className="rounded-full bg-zinc-900 px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-white hover:bg-zinc-700"
                   >
                     Xem chi tiết
                   </Link>
                 </div>
              </div>
            </motion.article>
          ))}
        </motion.div>
      )}
    </section>
  )
}

export default ProductSection

import React, { useEffect, useState } from 'react'
import { Link, useParams, useNavigate } from 'react-router-dom'
import toast from 'react-hot-toast'
import { getProductDetail } from '../services/productService'
import { addToCart } from '../services/cartService'
import { getAuthSession } from '../services/sessionService'

function formatPrice(value) {
  return new Intl.NumberFormat('vi-VN', {
    style: 'currency',
    currency: 'VND',
    maximumFractionDigits: 0,
  }).format(value || 0)
}

function ProductDetailPage() {
  const { productId } = useParams()
  const navigate = useNavigate()
  const [product, setProduct] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [quantity, setQuantity] = useState(1)
  const [adding, setAdding] = useState(false)

  const session = getAuthSession()

  useEffect(() => {
    async function loadProduct() {
      setLoading(true)
      setError('')

      try {
        if (!productId) {
          throw new Error('Product ID khong hop le')
        }
        const data = await getProductDetail(productId)

        if (!data) {
          throw new Error('Khong nhan duoc du lieu san pham tu API')
        }

        if (typeof data !== 'object') {
          throw new Error(`Du lieu san pham khong hop le: ${typeof data}`)
        }

        if (!data.id) {
          throw new Error('San pham khong co ID')
        }

        setProduct(data)
        setQuantity(1)
      } catch (err) {
        setError(err?.message || 'Đã có lỗi khi tải sản phẩm')
      } finally {
        setLoading(false)
      }
    }

    loadProduct()
  }, [productId])

  const handleQuantityChange = (newQuantity) => {
    const value = Math.max(1, Math.min(newQuantity, product?.stock || 1))
    setQuantity(value)
  }

  const handleAddToCart = async () => {
    if (!session?.token) {
      toast.error('Vui lòng đăng nhập để thêm vào giỏ hàng')
      navigate('/login')
      return
    }

    if (!product || quantity < 1) {
      toast.error('Vui lòng chọn sản phẩm và số lượng hợp lệ')
      return
    }

    setAdding(true)

    try {
      const result = await addToCart(product.id, quantity)
      toast.success(`Đã thêm ${quantity} sản phẩm vào giỏ hàng`)
      setQuantity(1)
    } catch (err) {
      toast.error(err?.message || 'Không thể thêm vào giỏ hàng')
    } finally {
      setAdding(false)
    }
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-[linear-gradient(180deg,#f7f7f4_0%,#f4f4ef_45%,#ffffff_100%)] px-6 py-10">
        <div className="mx-auto w-full max-w-5xl">
          <p className="text-center text-sm text-zinc-600">Đang tải chi tiết sản phẩm...</p>
        </div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="min-h-screen bg-[linear-gradient(180deg,#f7f7f4_0%,#f4f4ef_45%,#ffffff_100%)] px-6 py-10">
        <div className="mx-auto w-full max-w-5xl">
          <div className="rounded-2xl border border-red-200 bg-red-50 p-6">
            <p className="text-sm font-semibold text-red-700">Lỗi khi tải sản phẩm:</p>
            <p className="mt-2 text-sm text-red-600 whitespace-pre-wrap break-words">{error}</p>
            <p className="mt-3 text-xs text-red-600">Product ID: {productId}</p>
            <p className="mt-1 text-xs text-red-600">API URL: http://localhost:8080/products/{productId}</p>
            <Link
              to="/products"
              className="mt-4 inline-block rounded-full border border-red-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-red-700 hover:border-red-500"
            >
              Quay lại danh sách
            </Link>
          </div>
        </div>
      </div>
    )
  }

  if (!product) {
    return (
      <div className="min-h-screen bg-[linear-gradient(180deg,#f7f7f4_0%,#f4f4ef_45%,#ffffff_100%)] px-6 py-10">
        <div className="mx-auto w-full max-w-5xl">
          <div className="rounded-2xl border border-zinc-200 bg-white p-6 text-center">
            <p className="text-sm text-zinc-600">Không tìm thấy sản phẩm này</p>
            <Link
              to="/products"
              className="mt-4 inline-block rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900"
            >
              Quay lại danh sách
            </Link>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-[linear-gradient(180deg,#f7f7f4_0%,#f4f4ef_45%,#ffffff_100%)] px-6 py-10">
      <div className="mx-auto w-full max-w-6xl">
        <Link
          to="/products"
          className="mb-6 inline-flex items-center gap-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-600 hover:text-zinc-900"
        >
          ← Quay lại
        </Link>

        <div className="grid gap-8 md:grid-cols-2">
          {/* Image Section */}
          <div className="flex items-center justify-center rounded-2xl border border-zinc-200 bg-white">
            {product.imageUrl ? (
              <img
                src={product.imageUrl}
                alt={product.name}
                className="h-full w-full rounded-2xl object-cover"
              />
            ) : (
              <div className="flex h-96 w-full items-center justify-center rounded-2xl bg-gradient-to-br from-zinc-200 to-zinc-100 text-sm font-semibold text-zinc-500">
                Chưa có ảnh sản phẩm
              </div>
            )}
          </div>

          {/* Details Section */}
          <div className="rounded-2xl border border-zinc-200 bg-white p-8">
            <div className="mb-4 flex items-start justify-between gap-3">
              <div>
                <p className="text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">
                  {product.categoryName || 'Danh mục'}
                </p>
                <h1 className="mt-2 text-3xl font-semibold tracking-tight text-zinc-900">
                  {product.name}
                </h1>
              </div>
              <span className="rounded-full border border-zinc-200 bg-zinc-100 px-3 py-1 text-xs font-semibold uppercase tracking-[0.15em] text-zinc-600">
                {product.status}
              </span>
            </div>

            {product.description && (
              <p className="mt-4 text-base text-zinc-700 leading-relaxed">
                {product.description}
              </p>
            )}

            {/* Product Info */}
            <div className="mt-6 space-y-3 border-t border-zinc-200 pt-6">
              <div className="flex justify-between">
                <span className="text-sm text-zinc-600">Người bán:</span>
                <span className="font-medium text-zinc-900">{product.sellerUsername}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-sm text-zinc-600">Tồn kho:</span>
                <span className="font-medium text-zinc-900">{product.stock} sản phẩm</span>
              </div>
              <div className="flex justify-between">
                <span className="text-sm text-zinc-600">ID Sản phẩm:</span>
                <span className="font-medium text-zinc-900">#{product.id}</span>
              </div>
            </div>

            {/* Price */}
            <div className="mt-6 border-t border-zinc-200 pt-6">
              <p className="text-4xl font-bold text-zinc-900">
                {formatPrice(product.price)}
              </p>
            </div>

            {/* Quantity Selector */}
            <div className="mt-6 border-t border-zinc-200 pt-6">
              <p className="mb-3 text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">
                Số lượng
              </p>
              <div className="flex items-center gap-3">
                <button
                  onClick={() => handleQuantityChange(quantity - 1)}
                  className="h-10 w-10 rounded-full border border-zinc-300 bg-white hover:border-zinc-900 hover:bg-zinc-50 flex items-center justify-center font-semibold text-zinc-900"
                  disabled={quantity <= 1}
                >
                  −
                </button>
                <input
                  type="number"
                  value={quantity}
                  onChange={(e) => handleQuantityChange(parseInt(e.target.value) || 1)}
                  className="w-16 rounded-lg border border-zinc-300 bg-white px-3 py-2 text-center font-medium text-zinc-900"
                  min="1"
                  max={product.stock}
                />
                <button
                  onClick={() => handleQuantityChange(quantity + 1)}
                  className="h-10 w-10 rounded-full border border-zinc-300 bg-white hover:border-zinc-900 hover:bg-zinc-50 flex items-center justify-center font-semibold text-zinc-900"
                  disabled={quantity >= product.stock}
                >
                  +
                </button>
              </div>
            </div>

            {/* Add to Cart Button */}
            <button
              onClick={handleAddToCart}
              disabled={adding || product.stock === 0}
              className="mt-6 w-full rounded-full bg-zinc-900 px-6 py-3 text-sm font-semibold uppercase tracking-[0.14em] text-white hover:bg-zinc-700 disabled:bg-zinc-400 disabled:cursor-not-allowed transition-colors"
            >
              {adding ? 'Đang thêm...' : product.stock === 0 ? 'Hết hàng' : 'Thêm vào giỏ hàng'}
            </button>

            {!session?.token && (
              <Link
                to="/login"
                className="mt-3 block w-full rounded-full border border-zinc-300 bg-white px-6 py-3 text-center text-sm font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900 hover:bg-zinc-50 transition-colors"
              >
                Đăng nhập để mua
              </Link>
            )}
          </div>
        </div>
      </div>
    </div>
  )
}

export default ProductDetailPage

import React, { useEffect, useState } from 'react'
import { Link, useParams, useNavigate } from 'react-router-dom'
import toast from 'react-hot-toast'
import { getProductDetail, getProducts } from '../services/productService'
import { addToCart } from '../services/cartService'
import { getAuthSession } from '../services/sessionService'

function formatPrice(value) {
  return new Intl.NumberFormat('vi-VN', {
    style: 'currency',
    currency: 'VND',
    maximumFractionDigits: 0,
  }).format(value || 0)
}

function ProductDetailPage() {
  const { productId } = useParams()
  const navigate = useNavigate()
  const [product, setProduct] = useState(null)
  const [loading, setLoading] = useState(true)
  const [error, setError] = useState('')
  const [quantity, setQuantity] = useState(1)
  const [adding, setAdding] = useState(false)
  const [relatedProducts, setRelatedProducts] = useState([])

  const session = getAuthSession()

  useEffect(() => {
    async function loadProduct() {
      setLoading(true)
      setError('')

      try {
        if (!productId) {
          throw new Error('Product ID khong hop le')
        }
        const data = await getProductDetail(productId)

        if (!data) {
          throw new Error('Khong nhan duoc du lieu san pham tu API')
        }

        if (typeof data !== 'object') {
          throw new Error(`Du lieu san pham khong hop le: ${typeof data}`)
        }

        if (!data.id) {
          throw new Error('San pham khong co ID')
        }

        setProduct(data)
        setQuantity(1)

        const allProducts = await getProducts()
        const sameCategory = allProducts
          .filter((item) => item?.id !== data.id && item?.categoryId === data?.categoryId)
          .sort((a, b) => {
            const byViews = Number(b?.viewCount || 0) - Number(a?.viewCount || 0)
            if (byViews !== 0) return byViews
            return Number(b?.id || 0) - Number(a?.id || 0)
          })

        setRelatedProducts(sameCategory)
      } catch (err) {
        setError(err?.message || 'Đã có lỗi khi tải sản phẩm')
        setRelatedProducts([])
      } finally {
        setLoading(false)
      }
    }

    loadProduct()
  }, [productId])

  const handleQuantityChange = (newQuantity) => {
    const value = Math.max(1, Math.min(newQuantity, product?.stock || 1))
    setQuantity(value)
  }

  const handleAddToCart = async () => {
    if (!session?.token) {
      toast.error('Vui lòng đăng nhập để thêm vào giỏ hàng')
      navigate('/login')
      return
    }

    if (!product || quantity < 1) {
      toast.error('Vui lòng chọn sản phẩm và số lượng hợp lệ')
      return
    }

    setAdding(true)

    try {
      const result = await addToCart(product.id, quantity)
      toast.success(`Đã thêm ${quantity} sản phẩm vào giỏ hàng`)
      setQuantity(1)
    } catch (err) {
      toast.error(err?.message || 'Không thể thêm vào giỏ hàng')
    } finally {
      setAdding(false)
    }
  }

  if (loading) {
    return (
      <div className="min-h-screen bg-[linear-gradient(180deg,#f7f7f4_0%,#f4f4ef_45%,#ffffff_100%)] px-6 py-10">
        <div className="mx-auto w-full max-w-5xl">
          <p className="text-center text-sm text-zinc-600">Đang tải chi tiết sản phẩm...</p>
        </div>
      </div>
    )
  }

  if (error) {
    return (
      <div className="min-h-screen bg-[linear-gradient(180deg,#f7f7f4_0%,#f4f4ef_45%,#ffffff_100%)] px-6 py-10">
        <div className="mx-auto w-full max-w-5xl">
          <div className="rounded-2xl border border-red-200 bg-red-50 p-6">
            <p className="text-sm font-semibold text-red-700">Lỗi khi tải sản phẩm:</p>
            <p className="mt-2 text-sm text-red-600 whitespace-pre-wrap break-words">{error}</p>
            <p className="mt-3 text-xs text-red-600">Product ID: {productId}</p>
            <p className="mt-1 text-xs text-red-600">API URL: http://localhost:8080/products/{productId}</p>
            <Link
              to="/products"
              className="mt-4 inline-block rounded-full border border-red-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-red-700 hover:border-red-500"
            >
              Quay lại danh sách
            </Link>
          </div>
        </div>
      </div>
    )
  }

  if (!product) {
    return (
      <div className="min-h-screen bg-[linear-gradient(180deg,#f7f7f4_0%,#f4f4ef_45%,#ffffff_100%)] px-6 py-10">
        <div className="mx-auto w-full max-w-5xl">
          <div className="rounded-2xl border border-zinc-200 bg-white p-6 text-center">
            <p className="text-sm text-zinc-600">Không tìm thấy sản phẩm này</p>
            <Link
              to="/products"
              className="mt-4 inline-block rounded-full border border-zinc-300 bg-white px-4 py-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900"
            >
              Quay lại danh sách
            </Link>
          </div>
        </div>
      </div>
    )
  }

  return (
    <div className="min-h-screen bg-[linear-gradient(180deg,#f7f7f4_0%,#f4f4ef_45%,#ffffff_100%)] px-6 py-10">
      <div className="mx-auto w-full max-w-6xl">
        <Link
          to="/products"
          className="mb-6 inline-flex items-center gap-2 text-xs font-semibold uppercase tracking-[0.14em] text-zinc-600 hover:text-zinc-900"
        >
          ← Quay lại
        </Link>

        <div className="grid gap-8 md:grid-cols-2">
          {/* Image Section */}
          <div className="flex items-center justify-center rounded-2xl border border-zinc-200 bg-white">
            {product.imageUrl ? (
              <img
                src={product.imageUrl}
                alt={product.name}
                className="h-full w-full rounded-2xl object-cover"
              />
            ) : (
              <div className="flex h-96 w-full items-center justify-center rounded-2xl bg-gradient-to-br from-zinc-200 to-zinc-100 text-sm font-semibold text-zinc-500">
                Chưa có ảnh sản phẩm
              </div>
            )}
          </div>

          {/* Details Section */}
          <div className="rounded-2xl border border-zinc-200 bg-white p-8">
            <div className="mb-4 flex items-start justify-between gap-3">
              <div>
                <p className="text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">
                  {product.categoryName || 'Danh mục'}
                </p>
                <h1 className="mt-2 text-3xl font-semibold tracking-tight text-zinc-900">
                  {product.name}
                </h1>
              </div>
              <span className="rounded-full border border-zinc-200 bg-zinc-100 px-3 py-1 text-xs font-semibold uppercase tracking-[0.15em] text-zinc-600">
                {product.status}
              </span>
            </div>

            {product.description && (
              <p className="mt-4 text-base text-zinc-700 leading-relaxed">
                {product.description}
              </p>
            )}

            {/* Product Info */}
            <div className="mt-6 space-y-3 border-t border-zinc-200 pt-6">
              <div className="flex justify-between">
                <span className="text-sm text-zinc-600">Người bán:</span>
                <span className="font-medium text-zinc-900">{product.sellerUsername}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-sm text-zinc-600">Tồn kho:</span>
                <span className="font-medium text-zinc-900">{product.stock} sản phẩm</span>
              </div>
              <div className="flex justify-between">
                <span className="text-sm text-zinc-600">ID Sản phẩm:</span>
                <span className="font-medium text-zinc-900">#{product.id}</span>
              </div>
              <div className="flex justify-between">
                <span className="text-sm text-zinc-600">Lượt xem:</span>
                <span className="font-medium text-zinc-900">{Number(product.viewCount || 0).toLocaleString('vi-VN')}</span>
              </div>
            </div>

            {/* Price */}
            <div className="mt-6 border-t border-zinc-200 pt-6">
              <p className="text-4xl font-bold text-zinc-900">
                {formatPrice(product.price)}
              </p>
            </div>

            {/* Quantity Selector */}
            <div className="mt-6 border-t border-zinc-200 pt-6">
              <p className="mb-3 text-xs font-semibold uppercase tracking-[0.18em] text-zinc-500">
                Số lượng
              </p>
              <div className="flex items-center gap-3">
                <button
                  onClick={() => handleQuantityChange(quantity - 1)}
                  className="h-10 w-10 rounded-full border border-zinc-300 bg-white hover:border-zinc-900 hover:bg-zinc-50 flex items-center justify-center font-semibold text-zinc-900"
                  disabled={quantity <= 1}
                >
                  −
                </button>
                <input
                  type="number"
                  value={quantity}
                  onChange={(e) => handleQuantityChange(parseInt(e.target.value) || 1)}
                  className="w-16 rounded-lg border border-zinc-300 bg-white px-3 py-2 text-center font-medium text-zinc-900"
                  min="1"
                  max={product.stock}
                />
                <button
                  onClick={() => handleQuantityChange(quantity + 1)}
                  className="h-10 w-10 rounded-full border border-zinc-300 bg-white hover:border-zinc-900 hover:bg-zinc-50 flex items-center justify-center font-semibold text-zinc-900"
                  disabled={quantity >= product.stock}
                >
                  +
                </button>
              </div>
            </div>

            {/* Add to Cart Button */}
            <button
              onClick={handleAddToCart}
              disabled={adding || product.stock === 0}
              className="mt-6 w-full rounded-full bg-zinc-900 px-6 py-3 text-sm font-semibold uppercase tracking-[0.14em] text-white hover:bg-zinc-700 disabled:bg-zinc-400 disabled:cursor-not-allowed transition-colors"
            >
              {adding ? 'Đang thêm...' : product.stock === 0 ? 'Hết hàng' : 'Thêm vào giỏ hàng'}
            </button>

            {!session?.token && (
              <Link
                to="/login"
                className="mt-3 block w-full rounded-full border border-zinc-300 bg-white px-6 py-3 text-center text-sm font-semibold uppercase tracking-[0.14em] text-zinc-800 hover:border-zinc-900 hover:bg-zinc-50 transition-colors"
              >
                Đăng nhập để mua
              </Link>
            )}
          </div>
        </div>

        {relatedProducts.length > 0 && (
          <section className="mt-10 rounded-2xl border border-zinc-200 bg-white p-6">
            <div className="flex items-center justify-between gap-3">
              <h2 className="text-xl font-semibold tracking-tight text-zinc-900">Sản phẩm liên quan</h2>
              <p className="text-xs font-semibold uppercase tracking-[0.14em] text-zinc-500">
                Cùng danh mục, ưu tiên lượt xem cao
              </p>
            </div>

            <div className="mt-4 flex gap-4 overflow-x-auto pb-2">
              {relatedProducts.map((item) => (
                <article
                  key={item.id}
                  className="min-w-[240px] rounded-2xl border border-zinc-200 bg-zinc-50 p-4 md:min-w-[280px] lg:min-w-[calc((100%-3rem)/4)]"
                >
                  <Link to={`/products/${item.id}`} className="block">
                    <div className="h-36 overflow-hidden rounded-xl bg-zinc-100">
                      {item.imageUrl ? (
                        <img src={item.imageUrl} alt={item.name} className="h-full w-full object-cover" />
                      ) : (
                        <div className="flex h-full w-full items-center justify-center text-xs font-semibold text-zinc-500">
                          Chưa có ảnh
                        </div>
                      )}
                    </div>

                    <h3 className="mt-3 line-clamp-2 text-sm font-semibold text-zinc-900">{item.name}</h3>
                    <p className="mt-1 text-sm font-semibold text-zinc-900">{formatPrice(item.price)}</p>
                    <p className="mt-1 text-xs text-zinc-600">Lượt xem: {Number(item.viewCount || 0).toLocaleString('vi-VN')}</p>
                  </Link>
                </article>
              ))}
            </div>
          </section>
        )}
      </div>
    </div>
  )
}

export default ProductDetailPage
